solution:
struct Book<'a> {
    author: &'a str,
    title: &'a str,
}

fn main() {
    let name = String::from("Jill Smith");
    let title = String::from("Fish Fly");
    let book = Book {
        author: &name,
        title: &title,
    };
    println!("{} by {}", book.title, book.author);
}
